import{_ as a}from"./chunks/DemoViewer.vue_vue_type_script_setup_true_lang.BkXGR8Pr.js";import{w as s,x as t,y as i,z as n}from"./chunks/theme.BubYwfvn.js";import{u as o}from"./chunks/links.AjectzQB.js";import{a3 as c,o as l,c as h,p as r,a as p,v,ah as d}from"./chunks/framework.DKbJLo0O.js";import"./chunks/index.DQM0ZPc0.js";const j=JSON.parse('{"title":"JSON Canvas Viewer","description":"JSON Canvas Viewer 是一个前端库，提供可扩展的 JSON Canvas 查看器，能够轻松集成到任何现有框架和范式中。","frontmatter":{"title":"JSON Canvas Viewer","description":"JSON Canvas Viewer 是一个前端库，提供可扩展的 JSON Canvas 查看器，能够轻松集成到任何现有框架和范式中。","layout":"project","logo":"https://github.com/hesprs/json-canvas-viewer/raw/main/assets/logo.svg"},"headers":[],"relativePath":"zh-Hans/projects/json-canvas-viewer.md","filePath":"zh-Hans/projects/json-canvas-viewer.md","lastUpdated":1775407704000}'),u={name:"zh-Hans/projects/json-canvas-viewer.md"},S=c({...u,setup(g){return o([{name:"GitHub",url:"https://github.com/hesprs/json-canvas-viewer",icon:s,color:"#010409"},{name:"npm",url:"https://www.npmjs.com/package/json-canvas-viewer",icon:t,color:"#EA2039"},{name:"文档",url:"https://github.com/hesprs/json-canvas-viewer/wiki",icon:i,color:"#425aef"},{name:"JSON Canvas",url:"https://jsoncanvas.org",icon:n,color:"#8B0A5F"}]),(m,e)=>(l(),h("div",null,[e[0]||(e[0]=r("h2",{id:"演示",tabindex:"-1"},[p("演示 "),r("a",{class:"header-anchor",href:"#演示","aria-label":"Permalink to “演示”"},"​")],-1)),v(a),e[1]||(e[1]=d('<p>上方展示 JSON Canvas Viewer 架构的插图即为该查看器自身的实例，已加载 <a href="https://github.com/hesprs/json-canvas-viewer/wiki/3-%F0%9F%A7%A9-Modules#minimap" target="_blank" rel="noreferrer"><code>Minimap</code></a>、<a href="https://github.com/hesprs/json-canvas-viewer/wiki/3-%F0%9F%A7%A9-Modules#controls" target="_blank" rel="noreferrer"><code>Controls</code></a> 和 <a href="https://github.com/hesprs/json-canvas-viewer/wiki/3-%F0%9F%A7%A9-Modules#mistouch-preventer" target="_blank" rel="noreferrer"><code>MistouchPreventer</code></a> 模块。</p><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to “简介”">​</a></h2><p><a href="https://obsidian.md" target="_blank" rel="noreferrer">Obsidian</a> 提供了一款名为 <a href="https://jsoncanvas.org" target="_blank" rel="noreferrer">JSON Canvas</a> 的强大工具，它使我能够以非线性方式思考，非常适合用于复杂状态机或依赖关系图等场景。虽然它在个人使用上已足够，但很难与他人分享，因为目前尚无成熟的方法可在 Obsidian 外部查看这些内容。</p><p><code>JSON Canvas Viewer</code> 正是为解决此问题而生。它是一个基于 TypeScript 的 JSON Canvas 文件查看器，使用户可以直接在浏览器中查看和交互画布，或轻松将查看器嵌入网站。它不依赖任何特定框架构建，因此可轻易集成至任意框架中。</p><h2 id="特性" tabindex="-1">特性 <a class="header-anchor" href="#特性" aria-label="Permalink to “特性”">​</a></h2><ul><li>在网页浏览器中查看 JSON Canvas 文件（<code>.canvas</code>）</li><li>可轻松嵌入网站</li><li>支持交互式的平移与缩放功能</li><li>能够完整显示 <a href="https://jsoncanvas.org/spec/1.0/" target="_blank" rel="noreferrer">官方规范</a> 中定义的所有画布特性</li><li>响应式设计，适配移动端与触控板操作</li><li>支持懒加载</li><li>原生支持 TypeScript</li><li>具备现代美学设计，支持亮色与暗色模式</li><li>提供专为快速试用设计的 <a href="https://github.com/hesprs/json-canvas-viewer/wiki/1-%F0%9F%9A%80-Quick-Start#-chimpanzee-version" target="_blank" rel="noreferrer">chimp 版本</a></li><li>🔥 性能优于在 Obsidian 中渲染画布！</li><li>🧩 由 <a href="/zh-Hans/researches/synthkernel">SynthKernel</a> 架构驱动的开箱即用式可扩展性与摇树优化，当前可选模块包括： <ul><li><a href="https://github.com/hesprs/json-canvas-viewer/wiki/3-%F0%9F%A7%A9-Modules#minimap" target="_blank" rel="noreferrer"><code>Minimap</code></a>：便于导航</li><li><a href="https://github.com/hesprs/json-canvas-viewer/wiki/3-%F0%9F%A7%A9-Modules#controls" target="_blank" rel="noreferrer"><code>Controls</code></a>：显示缩放及全屏按钮</li><li><a href="https://github.com/hesprs/json-canvas-viewer/wiki/3-%F0%9F%A7%A9-Modules#mistouch-preventer" target="_blank" rel="noreferrer"><code>MistouchPreventer</code></a>：防止画布干扰页面滚动</li><li><a href="https://github.com/hesprs/json-canvas-viewer/wiki/3-%F0%9F%A7%A9-Modules#debug-panel" target="_blank" rel="noreferrer"><code>DebugPanel</code></a>：显示缩放比例与位置数据</li></ul></li></ul><h2 id="集成" tabindex="-1">集成 <a class="header-anchor" href="#集成" aria-label="Permalink to “集成”">​</a></h2><p>JSON Canvas Viewer 目前可无缝集成以下技术栈 / 技术（包括但不限于）：</p><ul><li>✅ <strong>原生 JS/TS</strong>: <a href="https://github.com/hesprs/json-canvas-viewer/wiki/1-%F0%9F%9A%80-Quick-Start#vanilla-jsts" target="_blank" rel="noreferrer">原生支持</a> - <code>json-canvas-viewer</code></li><li>✅ <strong>预渲染</strong>: <a href="https://github.com/hesprs/json-canvas-viewer/wiki/4-%F0%9F%96%87%EF%B8%8F-Prerendering" target="_blank" rel="noreferrer"><code>renderToString</code></a> - <code>json-canvas-viewer</code></li><li>✅ <strong>Vite</strong>: <a href="https://github.com/hesprs/json-canvas-viewer/wiki/1-%F0%9F%9A%80-Quick-Start#vite" target="_blank" rel="noreferrer">Vite 插件</a> - <code>vite-plugin-json-canvas</code></li><li>✅ <strong>Vue</strong>: <a href="https://github.com/hesprs/json-canvas-viewer/wiki/1-%F0%9F%9A%80-Quick-Start#vue" target="_blank" rel="noreferrer">Vue 组件</a> - <code>@json-canvas-viewer/vue</code></li><li>✅ <strong>React</strong>: <a href="https://github.com/hesprs/json-canvas-viewer/wiki/1-%F0%9F%9A%80-Quick-Start#react" target="_blank" rel="noreferrer">React 组件</a> - <code>@json-canvas-viewer/react</code></li><li>✅ <strong>Preact</strong>: <a href="https://github.com/hesprs/json-canvas-viewer/wiki/1-%F0%9F%9A%80-Quick-Start#preact" target="_blank" rel="noreferrer">Preact 组件</a> - <code>@json-canvas-viewer/preact</code></li></ul><p>了解更多关于 JSON Canvas Viewer 的信息，请访问 <a href="https://github.com/hesprs/json-canvas-viewer" target="_blank" rel="noreferrer">GitHub 仓库</a>。</p><h2 id="许可证" tabindex="-1">许可证 <a class="header-anchor" href="#许可证" aria-label="Permalink to “许可证”">​</a></h2><p>JSON Canvas Viewer 采用 <a href="https://mit-license.org/" target="_blank" rel="noreferrer">MIT 许可证</a> 授权。</p>',12))]))}});export{j as __pageData,S as default};
